You can actually make this:
struct objEntry
{
	int objIdx;
	int X;
	int Y;
	int Z;
	int unk1;
	int angle;
	int pX1;
	int pY1;
	int pZ1;
	int pX2;
	int pY2;
	int pZ2;
};
